module RefModule (
    input clk,
    input reset,
    output [4:0] q );reg [4:0] obf_count_reg;

always @(posedge clk) begin
    if (reset)
        obf_count_reg <= 5'b00000;
    else
        obf_count_reg <= {obf_count_reg[3:0], ~obf_count_reg[4]};
end

assign q = obf_count_reg;

endmodule
